interface BookCard {
  model: string;
  year: string;
  headrest: string;
  armrest: string;
  qty: number;
  imageName: string;
  imageUrl: string;
  description: string;
}

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  cards: BookCard[] = [];
  errorMessage = '';
  allImageUrls: string[] = [];
  allManifestImages: string[] = [];

  selectedModelName = '';
  selectedModelImages: string[] = [];

  modelOptions: string[] = [];
  yearOptions: string[] = [];
  headrestOptions: string[] = [];
  armrestOptions: string[] = [];

  selectedModel = '';
  selectedYear = '';
  selectedHeadrest = '';
  selectedArmrest = '';

  constructor(private readonly http: HttpClient) {}

  ngOnInit(): void {
    this.loadImageManifest();
    this.loadCsvData();
  }

  private loadImageManifest(): void {
    this.http.get<string[]>('assets/images/image-manifest.json').subscribe(
      (manifestImages) => {
        this.allManifestImages = manifestImages.map((img) => 'assets/images/' + img);
      },
      () => {
        // Manifest not found, gallery will use CSV-only images
        this.allManifestImages = [];
      }
    );
  }

  private loadCsvData(): void {
    this.http.get('assets/images/book.csv', { responseType: 'text' }).subscribe(
      (csvText) => {
        this.loadCards(csvText);
      },
      () => {
        if (window.location.protocol === 'file:') {
          this.loadCards(FALLBACK_BOOK_CSV);
          this.errorMessage = '';
          return;
        }
        this.errorMessage = 'Unable to load assets/images/book.csv';
      }
    );
  }

  private loadCards(csvText: string): void {
    const parsedCards = this.mapCardsFromCsv(csvText);
    this.allImageUrls = this.buildImageCatalogFromCards(parsedCards);
    this.cards = parsedCards.map((card) => ({
      ...card,
      imageUrl: this.resolvePrimaryImageUrl(card.imageName, card.model)
    }));
    this.initializeFilterOptions();
  }

  get filteredCards(): BookCard[] {
    return this.cards.filter((card) =>
      card.qty > 0 &&
      this.matchesFilter(card.model, this.selectedModel) &&
      this.matchesFilter(card.year, this.selectedYear) &&
      this.matchesFilter(card.headrest, this.selectedHeadrest) &&
      this.matchesFilter(card.armrest, this.selectedArmrest)
    );
  }

  clearFilters(): void {
    this.selectedModel = '';
    this.selectedYear = '';
    this.selectedHeadrest = '';
    this.selectedArmrest = '';
  }

  goBack(): void {
    this.selectedModelName = '';
    this.selectedModelImages = [];
  }

  onCardClick(card: BookCard): void {
    this.selectedModelName = card.model;
    this.selectedModelImages = this.getImagesFromFolder(card.imageName);

    if (this.selectedModelImages.length === 0) {
      this.selectedModelImages = this.getCardImageUrls(card.imageName, card.model);
    }

    if (this.selectedModelImages.length === 0) {
      this.selectedModelImages = [card.imageUrl];
    }
  }

  private getImagesFromFolder(imageName: string): string[] {
    const folderPrefix = this.getFolderPrefix(imageName);
    if (!folderPrefix) {
      return [];
    }

    // First, try to get all images from the manifest
    const manifestMatches = this.allManifestImages.filter((imageUrl) => {
      const relativePath = imageUrl.replace(/^assets\/images\//i, '').toLowerCase();
      return relativePath.indexOf(folderPrefix) === 0;
    });

    if (manifestMatches.length > 0) {
      return Array.from(new Set(manifestMatches));
    }

    // Fall back to CSV-based images if manifest is not available
    const csvMatches = this.allImageUrls.filter((imageUrl) => {
      const relativePath = imageUrl.replace(/^assets\/images\//i, '').toLowerCase();
      return relativePath.indexOf(folderPrefix) === 0;
    });

    return Array.from(new Set(csvMatches));
  }

  private getCardImageUrls(imageName: string, modelName: string): string[] {
    const imageBaseName = this.getFileNameWithoutExtension(imageName);
    const normalizedBaseName = this.normalizeText(imageBaseName);
    const normalizedModel = this.normalizeText(modelName);

    if (!normalizedBaseName && !normalizedModel) {
      return [];
    }

    const matches = this.allImageUrls.filter((imageUrl) => {
      const pathWithoutRoot = imageUrl.replace(/^assets\/images\//i, '');
      const segments = pathWithoutRoot.split('/');
      const folderMatches = segments.slice(0, -1).some((segment) => {
        const normalizedSegment = this.normalizeText(segment);
        return normalizedSegment === normalizedBaseName || normalizedSegment.indexOf(normalizedBaseName) !== -1 || normalizedSegment.indexOf(normalizedModel) !== -1;
      });

      const fileName = segments[segments.length - 1] || '';
      const fileNameWithoutExtension = this.getFileNameWithoutExtension(fileName);
      const normalizedFileName = this.normalizeText(fileNameWithoutExtension);
      const fileMatches = normalizedFileName === normalizedBaseName || normalizedFileName.indexOf(normalizedBaseName) !== -1 || normalizedFileName.indexOf(normalizedModel) !== -1;

      return folderMatches || fileMatches;
    });

    return Array.from(new Set(matches));
  }

  private resolvePrimaryImageUrl(imageName: string, modelName: string): string {
    const folderPrefix = this.getFolderPrefix(imageName);
    if (folderPrefix) {
      const coverImage = this.allImageUrls.find((imageUrl) => {
        const relativePath = imageUrl.replace(/^assets\/images\//i, '').toLowerCase();
        return relativePath === folderPrefix + 'cover.jpeg';
      });

      if (coverImage) {
        return coverImage;
      }
    }

    const exactMatch = this.allImageUrls.find((imageUrl) =>
      imageUrl.toLowerCase().endsWith('/' + imageName.toLowerCase())
    );

    if (exactMatch) {
      return exactMatch;
    }

    const modelMatches = this.getCardImageUrls(imageName, modelName);
    if (modelMatches.length > 0) {
      return modelMatches[0];
    }

    return this.toAssetImageUrl(imageName);
  }

  private toAssetImageUrl(imageName: string): string {
    return 'assets/images/' + (imageName || '').replace(/^\/+/, '');
  }

  private buildImageCatalogFromCards(cards: BookCard[]): string[] {
    const imageSet: { [key: string]: boolean } = {};
    const imageList: string[] = [];

    cards.forEach((card) => {
      const primaryImage = this.toAssetImageUrl(card.imageName);
      if (!imageSet[primaryImage]) {
        imageSet[primaryImage] = true;
        imageList.push(primaryImage);
      }

      const folderPrefix = this.getFolderPrefix(card.imageName);
      if (folderPrefix) {
        const coverImage = 'assets/images/' + folderPrefix + 'cover.jpeg';
        if (!imageSet[coverImage]) {
          imageSet[coverImage] = true;
          imageList.push(coverImage);
        }
      }
    });

    return imageList;
  }

  private getFolderPrefix(imageName: string): string {
    const normalizedPath = (imageName || '').replace(/^\/+/, '');
    const lastSlashIndex = normalizedPath.lastIndexOf('/');

    if (lastSlashIndex < 0) {
      return '';
    }

    return normalizedPath.slice(0, lastSlashIndex + 1).toLowerCase();
  }

  private normalizeText(value: string): string {
    return (value || '').toLowerCase().replace(/[^a-z0-9]/g, '');
  }

  private getFileNameWithoutExtension(fileName: string): string {
    return fileName.replace(/\.[^/.]+$/, '');
  }

  private matchesFilter(value: string, selectedValue: string): boolean {
    if (!selectedValue) {
      return true;
    }
    return (value || '').toLowerCase() === selectedValue.toLowerCase();
  }

  private initializeFilterOptions(): void {
    this.modelOptions = this.extractOptions((card) => card.model);
    this.yearOptions = this.extractOptions((card) => card.year);
    this.headrestOptions = this.extractOptions((card) => card.headrest);
    this.armrestOptions = this.extractOptions((card) => card.armrest);
  }

  private extractOptions(getter: (card: BookCard) => string): string[] {
    const optionMap: { [key: string]: string } = {};

    this.cards.forEach((card) => {
      const rawValue = getter(card).trim();
      if (!rawValue) {
        return;
      }
      const normalizedKey = rawValue.toLowerCase();
      if (!optionMap[normalizedKey]) {
        optionMap[normalizedKey] = rawValue;
      }
    });

    return Object.keys(optionMap)
      .map((key) => optionMap[key])
      .sort((a, b) => a.localeCompare(b));
  }

  private mapCardsFromCsv(csvText: string): BookCard[] {
    const rows = this.parseCsv(csvText);
    if (rows.length <= 1) {
      return [];
    }

    const headers = rows[0].map((header) => header.trim());
    const modelIndex = this.findHeaderIndex(headers, ['Model']);
    const yearIndex = this.findHeaderIndex(headers, ['Year']);
    const headrestIndex = this.findHeaderIndex(headers, ['Headrest', 'HeadReast']);
    const armrestIndex = this.findHeaderIndex(headers, ['Armrest']);
    const qtyIndex = this.findHeaderIndex(headers, ['Qty', 'Quantity']);
    const imageIndex = this.findHeaderIndex(headers, ['Image', 'ImageName', 'ImageFile']);

    return rows.slice(1)
      .filter((row) => row.some((cell) => cell.trim().length > 0))
      .map((row) => {
        const model = this.getCell(row, modelIndex, 'Unknown');
        const year = this.getCell(row, yearIndex);
        const headrest = this.getCell(row, headrestIndex);
        const armrest = this.getCell(row, armrestIndex);
        const qty = this.getNumericCell(row, qtyIndex, 0);
        const imageName = this.getCell(row, imageIndex, '1.jpeg');
        const description = headers
          .map((header, index) => ({ header, value: this.getCell(row, index) }))
          .filter((item) => item.header !== 'Model' && item.header !== 'Qty' && item.header !== 'Quantity' && item.header !== 'Image' && item.header !== 'ImageName' && item.header !== 'ImageFile')
          .map((item) => item.header + ': ' + item.value)
          .join(' | ');

        return {
          model,
          year,
          headrest,
          armrest,
          qty,
          imageName,
          imageUrl: this.toAssetImageUrl(imageName),
          description
        };
      });
  }

  private findHeaderIndex(headers: string[], candidates: string[]): number {
    const normalizedCandidates = candidates.map((name) => name.toLowerCase());
    return headers.findIndex((header) => normalizedCandidates.indexOf(header.toLowerCase()) !== -1);
  }

  private getCell(row: string[], index: number, fallback: string = ''): string {
    if (index < 0 || index >= row.length) {
      return fallback;
    }
    return row[index].trim() || fallback;
  }

  private getNumericCell(row: string[], index: number, fallback: number): number {
    const rawValue = this.getCell(row, index, String(fallback));
    const parsedValue = parseInt(rawValue, 10);
    return isNaN(parsedValue) ? fallback : parsedValue;
  }

  private parseCsv(csvText: string): string[][] {
    const rows: string[][] = [];
    let currentRow: string[] = [];
    let currentCell = '';
    let inQuotes = false;

    for (let i = 0; i < csvText.length; i++) {
      const char = csvText[i];
      const nextChar = csvText[i + 1];

      if (char === '"') {
        if (inQuotes && nextChar === '"') {
          currentCell += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === ',' && !inQuotes) {
        currentRow.push(currentCell);
        currentCell = '';
      } else if ((char === '\n' || char === '\r') && !inQuotes) {
        if (char === '\r' && nextChar === '\n') {
          i++;
        }
        currentRow.push(currentCell);
        rows.push(currentRow);
        currentRow = [];
        currentCell = '';
      } else {
        currentCell += char;
      }
    }

    if (currentCell.length > 0 || currentRow.length > 0) {
      currentRow.push(currentCell);
      rows.push(currentRow);
    }

    return rows;
  }
}
